var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"끝까지 멍청하기 짝이 없군......","JPN":"最後まで愚か極まりないな……","ENG":"You never learn, do you...","TWN":"直到最後都是這麼愚蠢……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"넌 날 흡수한 시점에서 이미 완전한 존재가 됐어.","JPN":"貴様は私を吸収した時点ですでに完全な存在となっていた。","ENG":"You already became complete when you absorbed me.","TWN":"從妳吸收我之後，就已經成為完整的存在了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그런데 그깟 대원들 때문에 영원한 고통을 감수하겠다고?","JPN":"それなのに、くだらん隊員たちのために永遠の苦しみを引き受けるだと？","ENG":"And yet you choose to endure eternal pain for those fools?","TWN":"而妳現在卻為了那些隊員，甘心承受永遠的痛苦？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"내 원본이 이런 멍청이라니 그동안 집착했던 나까지 바보 같아지는군.","JPN":"オリジナルがここまで馬鹿だったとは、\\nこれまで拘ってきた私までもが愚かに思える。","ENG":"I can't believe my original would be so stupid. Now I feel dumb about obsessing over you so much.","TWN":"我的本體竟然如此愚蠢，搞得一直以來對妳如此執著的我，都像個笨蛋一樣。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭐, 됐어.","JPN":"まあ、いいだろう。","ENG":"Oh well.","TWN":"唉，算了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이렇게 된 거, 언제까지 고집을 부리나 네 안에서 지켜봐 주마.","JPN":"こうなったら、貴様がどこまで意地を通せるか、\\n貴様の内側から見届けてやる。","ENG":"I might as well as see how long you'll keep this up... as I lay inside you.","TWN":"既然妳決定這麼做，那我就看妳能堅持到什麼時候。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그거 알아, 류드밀라?","JPN":"ねぇ、知ってる？　リュドミラちゃん。","ENG":"You know what, Lyudmila?","TWN":"妳知道嗎，盧德米拉？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"실패작이었던 날 네가 구해 줬을 때, 뭐 이런 애가 다 있나 싶었어.","JPN":"失敗作だった私をリュドミラちゃんが助けてくれたとき、\\nおかしな子もいるものだと思ったわ。","ENG":"When you saved me, a failed product, I thought you were such a weirdo.","TWN":"當妳救了我這個失敗品時，我不禁懷疑世界上怎麼會有這樣的傢伙。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"관리국은 카운터가 중심인 조직인데, 넌 전대에 일반인부터 뽑아 왔으니까.","JPN":"管理局はカウンターが中心となる組織なのに、リュドミラちゃんは\\n戦隊に一般人を優先して起用したわよね。","ENG":"The Administration runs on Counters, but you recruited non-powered folks first into the division.","TWN":"管理局是一個制裁者為中心的組織，而妳卻從普通人開始選拔。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"기갑 병기가 중심이라 카운터는 별로 필요하지 않다고 해도, 그래서야 생환율이 떨어질 수밖에 없잖아.","JPN":"機甲兵器が主戦力だからカウンターはそんなに要らないとは\\nいっても、やっぱり高い生還率は見込めなくなっちゃうでしょ？","ENG":"Maybe we didn't need that many Counters with all the armored vehicles, but that would still lower our chance of survival.","TWN":"儘管以機械兵器為主的戰隊不是很需要制裁者，因為那樣會降低生存率。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"처음에는 쓰고 버리기 편한 부하들만 찾는 바보인 줄 알았는데......","JPN":"最初は使い捨てにしやすい部下を募るバカなのかと思ったけど……","ENG":"So at first, I thought you were just trying to stock up on easily expendable troops...","TWN":"所以一開始，我以為妳是個在利用完隊員後，就會把隊員丟棄的渾蛋……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"기록을 봤더니 우리 전대의 생환율이 관리국 전체 1위더라고.","JPN":"記録を見てみたら、うちの戦隊の生還率は管理局全体で\\n1位だったの。","ENG":"But when I checked out the database, our division had the highest rate of survival in the entire Administration.","TWN":"但是我看記錄後才發現，我們戰隊的生存率是管理局第一。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"심지어 그 콧대 높은 펜릴 전대보다 위였다니까?","JPN":"あのプライドの塊のフェンリル戦隊よりも上だったのよ？","ENG":"We even beat those revered guys from Fenrir!","TWN":"甚至比那個趾高氣昂的芬里爾戰隊還高。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그제서야 널 이해하게 됐어.","JPN":"それでようやく、アナタのことが理解できたわ。","ENG":"That's when I finally began to understand you.","TWN":"我那時才終於了解了妳。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"바보가 아니라, 아무도 신경 쓰지 않는 평범한 사람들이 죽거나 다치지 않게 최선을 다해 온 고집쟁이라는 걸.","JPN":"アナタはバカなんかじゃなかった。\\n誰も気にも留めない平凡なみんなを死や負傷から守りたくて、\\nそのために最善を尽くす意地っ張りだったのよね。","ENG":"You're not a fool. You're just a stubborn person who has been fighting to make sure ordinary folks that no one cares about don't have to die or get hurt.","TWN":"妳不是渾蛋，而是一個盡全力保護那些沒有人在乎的普通人，不讓他們死掉，或是受傷的死腦筋。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"남은 대원들도, 그리고 여기까지 오지 못한 대원들도......","JPN":"残された隊員たちも、そして、ここまで来られなかった隊員たちも……","ENG":"So all of us who are still here... and those that fell before us...","TWN":"剩下的隊員，還有沒能一起走到現在的隊員們……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모두 네게 고마워하고 있을 거야.","JPN":"みんながアナタに感謝してると思うわ。","ENG":"I'm sure they're all grateful to you.","TWN":"也都對妳心存感激。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러니까...... 이제 눈을 뜰 시간이야.","JPN":"だから……もうお目覚めの時間よ。","ENG":"So... you should wake up now.","TWN":"所以……快睜開眼睛吧。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};